const items = $input.all();

// Separate stores from store_insights by field presence
// stores have h3_r7 column; store_insights have store_id + categories
const stores = items.filter(i => typeof i.json.h3_r7 !== 'undefined');
const insightsMap = new Map(
  items
    .filter(i => typeof i.json.store_id !== 'undefined' && typeof i.json.categories !== 'undefined')
    .map(i => [i.json.store_id, i.json])
);

const WEIGHTS = { high: 1.0, medium: 0.6, low: 0.3 };

function extractWeighted(jsonb, weights) {
  if (!jsonb || typeof jsonb !== 'object') return [];
  const out = [];
  for (const [tier, w] of Object.entries(weights)) {
    const key = tier + '_confidence';
    for (const item of (Array.isArray(jsonb[key]) ? jsonb[key] : []))
      out.push({ name: String(item), weight: w });
  }
  return out;
}

const cellMap = new Map();

function getCell(h3Index, resolution, company_id) {
  const key = `${h3Index}::${resolution}::${company_id}`;
  if (!cellMap.has(key)) {
    cellMap.set(key, {
      h3_index: h3Index,
      resolution,
      company_id,
      store_count: 0,
      ratings: [],
      categoryScores: {},
      brandScores: {},
      dominantVotes: {}
    });
  }
  return cellMap.get(key);
}

for (const { json: store } of stores) {
  const { id, company_id, avg_rating, h3_r5, h3_r7, h3_r9 } = store;
  if (!company_id) continue;
  const rating = avg_rating != null ? parseFloat(avg_rating) : null;
  const insight = insightsMap.get(id) || null;

  for (const [h3Index, resolution] of [[h3_r5, 5], [h3_r7, 7], [h3_r9, 9]]) {
    if (!h3Index) continue;
    const cell = getCell(h3Index, resolution, company_id);
    cell.store_count++;
    if (rating !== null && !isNaN(rating)) cell.ratings.push(rating);

    if (insight) {
      if (insight.dominant_category)
        cell.dominantVotes[insight.dominant_category] =
          (cell.dominantVotes[insight.dominant_category] || 0) + 1;

      for (const { name, weight } of extractWeighted(insight.categories, WEIGHTS))
        cell.categoryScores[name] = (cell.categoryScores[name] || 0) + weight;

      for (const { name, weight } of extractWeighted(insight.brands, WEIGHTS))
        cell.brandScores[name] = (cell.brandScores[name] || 0) + weight;
    }
  }
}

// Whitespace: P95-relative density × rating-pressure
// P95 is the 95th-percentile store count across all cells in this run.
// This makes the ceiling data-relative — no hardcoded max.
const counts = Array.from(cellMap.values()).map(c => c.store_count).sort((a, b) => a - b);
const p95 = counts[Math.floor(counts.length * 0.95)] || counts[counts.length - 1] || 1;

function whitespace(storeCount, ratings) {
  const density = Math.min(storeCount / p95, 1.0);
  const avgRating = ratings.length
    ? ratings.reduce((a, b) => a + b, 0) / ratings.length
    : 0;
  // rating_pressure: 0.8–1.0. High-rated cells have stronger competition → lower whitespace.
  const pressure = 1 - 0.2 * (avgRating / 5.0);
  return Math.round(Math.max(0, Math.min(100, 100 * (1 - density) * pressure)) * 10) / 10;
}

return Array.from(cellMap.values()).map(cell => {
  const avgRating = cell.ratings.length
    ? Math.round(cell.ratings.reduce((a, b) => a + b, 0) / cell.ratings.length * 100) / 100
    : null;

  // dominant_category: category with the most votes across stores in the cell
  const dominantEntry = Object.entries(cell.dominantVotes).sort((a, b) => b[1] - a[1])[0];
  const dominant_category = dominantEntry ? dominantEntry[0] : null;

  // category_mix: normalise weighted scores to 0–1 relative to the highest scorer
  const maxCat = Math.max(...Object.values(cell.categoryScores), 1);
  const category_mix = Object.fromEntries(
    Object.entries(cell.categoryScores)
      .map(([k, v]) => [k, Math.round(v / maxCat * 1000) / 1000])
  );

  // brand_penetration: normalise weighted scores to 0–1 relative to the highest scorer
  const maxBrand = Math.max(...Object.values(cell.brandScores), 1);
  const brand_penetration = Object.fromEntries(
    Object.entries(cell.brandScores)
      .map(([k, v]) => [k, Math.round(v / maxBrand * 1000) / 1000])
  );

  return {
    json: {
      h3_index: cell.h3_index,
      resolution: cell.resolution,
      company_id: cell.company_id,
      store_count: cell.store_count,
      avg_rating: avgRating,
      dominant_category,
      brand_penetration,
      category_mix,
      whitespace_score: whitespace(cell.store_count, cell.ratings)
    }
  };
});
